package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import scala.util.{Try, Using}
import java.nio.file.{Path, Paths, Files}

@Singleton
class FileController @Inject()(val controllerComponents: ControllerComponents) extends BaseController {

  private val uploadsBaseDir: Path = Paths.get("uploads").toAbsolutePath.normalize()

  def serveFile(filename: String): Action[AnyContent] = Action { implicit request: Request[AnyContent] =>
    // Validate filename is not empty or blank
    if (filename == null || filename.trim.isEmpty) {
      BadRequest("Filename cannot be empty")
    } else {
      // Resolve the requested path and normalize to prevent path traversal
      val requestedPath: Path = uploadsBaseDir.resolve(filename).normalize()

      // Ensure the resolved path is still within the uploads directory (prevents path traversal attacks)
      if (!requestedPath.startsWith(uploadsBaseDir)) {
        Forbidden("Access denied: path traversal detected")
      }
      // Reject filenames containing null bytes
      else if (filename.contains('\u0000')) {
        BadRequest("Invalid filename")
      }
      // Reject paths with suspicious components
      else if (filename.split("[/\\\\]").exists(part => part == "." || part == "..")) {
        BadRequest("Invalid filename: relative path components not allowed")
      }
      // Check that the file exists and is a regular file (not a directory or symlink pointing outside)
      else if (!Files.exists(requestedPath) || !Files.isRegularFile(requestedPath)) {
        NotFound("File not found")
      }
      // Verify the real path (resolving symlinks) is still within uploads directory
      else if (!requestedPath.toRealPath().startsWith(uploadsBaseDir.toRealPath())) {
        Forbidden("Access denied: symlink outside allowed directory")
      }
      else {
        // Safely read the file content
        Using(Source.fromFile(requestedPath.toFile, "UTF-8")) { source =>
          val content = source.mkString
          // Determine a safe content type based on file extension
          val contentType = inferContentType(requestedPath.getFileName.toString)
          Ok(content).as(contentType)
        }.recover {
          case _: java.io.FileNotFoundException =>
            NotFound("File not found")
          case _: java.nio.charset.MalformedInputException =>
            UnsupportedMediaType("File is not a valid text file")
          case ex: Exception =>
            InternalServerError("Error reading file")
        }.get
      }
    }
  }

  private def inferContentType(filename: String): String = {
    val extension = filename.lastIndexOf('.') match {
      case -1 => ""
      case i  => filename.substring(i + 1).toLowerCase
    }
    extension match {
      case "txt"  => "text/plain; charset=utf-8"
      case "html" | "htm" => "text/plain; charset=utf-8" // Serve as plain text to prevent XSS
      case "css"  => "text/css; charset=utf-8"
      case "csv"  => "text/csv; charset=utf-8"
      case "json" => "application/json; charset=utf-8"
      case "xml"  => "application/xml; charset=utf-8"
      case "md"   => "text/plain; charset=utf-8"
      case "log"  => "text/plain; charset=utf-8"
      case _      => "application/octet-stream"
    }
  }
}